code.C:
#include <stdio.h>
int main() {
    for(int i=0;i<1;i++){
        printf("Polymorphism is the ability of objects of different classes to be accessed through the same interface, allowing the same operation to behave differently on different classes.\n");
        printf("In Python, polymorphism is mainly achieved through:\n");
        printf("1. Duck typing – if an object implements the required method/attribute, it can be used regardless of its actual type.\n");
        printf("2. Operator overloading – special methods like __add__, __len__, __str__ let built‑in operators work with user‑defined types.\n");
        printf("3. Method overriding – a subclass provides its own implementation of a method defined in the parent class.\n");
        printf("4. Method overloading – Python does not support true compile‑time overloading, but default arguments or *args/**kwargs can emulate it.\n");
    }
    return 0;
}

